const normalizeText = (value: string) => value.replace(/\s+/g, " ").trim();

const trimToWordBoundary = (value: string, maxLength: number) => {
  const clean = normalizeText(value);
  if (clean.length <= maxLength) return clean;
  const trimmed = clean.slice(0, maxLength);
  const lastSpace = trimmed.lastIndexOf(" ");
  return `${trimmed.slice(0, lastSpace > 0 ? lastSpace : maxLength).trim()}...`;
};

const deriveSeoKeywords = (post: BlogPost): string[] => {
  const category = post.category.toLowerCase();
  const titleWords = post.title
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, "")
    .split(/\s+/)
    .filter((word) => word.length > 3)
    .slice(0, 4);

  return Array.from(
    new Set([
      `${post.category.toLowerCase()} wishes`,
      `${post.category.toLowerCase()} ideas`,
      `${category} guide`,
      ...titleWords,
      "wishspark blog",
    ]),
  );
};

const enrichPost = (post: BlogPost): BlogPost => {
  const seoDescription = post.seoDescription
    ? trimToWordBoundary(post.seoDescription, 158)
    : trimToWordBoundary(
        `${post.excerpt} Read practical tips, examples, and celebration ideas on WishSpark.`,
        158,
      );

  return {
    ...post,
    seoTitle: post.seoTitle ?? trimToWordBoundary(`${post.title} | WishSpark Blog`, 58),
    seoDescription,
    seoKeywords: post.seoKeywords?.length ? post.seoKeywords : deriveSeoKeywords(post),
  };
};

export const blogPosts: BlogPost[] = baseBlogPosts.map(enrichPost);

export const getBlogPostBySlug = (slug: string): BlogPost | undefined => {
  return blogPosts.find(post => post.slug === slug);
};

export const getAuthorProfile = (authorName: string): AuthorProfile => {
  return authorProfiles[authorName] ?? {
    name: authorName,
    role: "WishSpark Contributor",
    focus: "Celebrations, greetings, and communication",
    bio: "Contributes practical and reader-first articles on greetings, festivals, and sharing culture.",
    profileUrl: "https://www.wishspark.xyz/about",
  };
};